{% if robokassa_graph_enabled %}
<script type="text/javascript">
(function() {
  function syncRobokassaCheckoutGraphs() {
    var graphContainers = document.querySelectorAll('.robokassa-checkout-graph');
    var activeMethods = [];

    for (var i = 0; i < graphContainers.length; i++) {
      var graphContainer = graphContainers[i];
      var radioWrapper = graphContainer.closest('.radio');
      var radioInput = radioWrapper ? radioWrapper.querySelector('input[name="payment_method"]') : null;
      var isActive = !!(radioInput && radioInput.checked);

      if (radioWrapper) {
        if (isActive) {
          radioWrapper.classList.add('robokassa-checkout-payment--active');
        } else {
          radioWrapper.classList.remove('robokassa-checkout-payment--active');
        }
      }

      if (isActive) {
        graphContainer.classList.add('is-active');

        if (graphContainer.getAttribute('data-payment-method')) {
          activeMethods.push(graphContainer.getAttribute('data-payment-method'));
        }
      } else {
        graphContainer.classList.remove('is-active');
      }
    }

    if (typeof window.initRobokassaGraphs === 'function' && activeMethods.length) {
      window.initRobokassaGraphs(activeMethods.length === 1 ? activeMethods[0] : activeMethods);
    }
  }

  function bindRobokassaCheckoutGraphs() {
    var radios = document.querySelectorAll('input[name="payment_method"]');

    for (var i = 0; i < radios.length; i++) {
      if (radios[i].getAttribute('data-robokassa-graph-bound') === '1') {
        continue;
      }

      radios[i].setAttribute('data-robokassa-graph-bound', '1');
      radios[i].addEventListener('change', syncRobokassaCheckoutGraphs);
    }
  }

  function initRobokassaCheckoutGraphs() {
    bindRobokassaCheckoutGraphs();
    syncRobokassaCheckoutGraphs();
  }

  if (window.__robokassaCheckoutGraphsLoading) {
    var waitInterval = window.setInterval(function() {
      if (typeof window.initRobokassaGraphs === 'function') {
        window.clearInterval(waitInterval);
        initRobokassaCheckoutGraphs();
      }
    }, 100);

    window.setTimeout(function() {
      window.clearInterval(waitInterval);
    }, 5000);

    return;
  }

  if (typeof window.initRobokassaGraphs === 'function') {
    initRobokassaCheckoutGraphs();
    return;
  }

  window.__robokassaCheckoutGraphsLoading = true;

  var script = document.createElement('script');
  script.src = '{{ robokassa_graph_script }}';
  script.onload = function() {
    window.__robokassaCheckoutGraphsLoading = false;
    initRobokassaCheckoutGraphs();
  };
  script.onerror = function() {
    window.__robokassaCheckoutGraphsLoading = false;
  };

  document.head.appendChild(script);
})();
</script>
<style>
 .robokassa-checkout-payment--active {
   padding: 12px 14px 14px;
   border: 1px solid #2f2f2f;
   border-radius: 8px;
   margin: 0 0 12px;
   box-sizing: border-box;
   overflow: visible;
 }

 .robokassa-checkout-payment--active > label {
   display: block;
   margin-bottom: 10px;
 }

 .robokassa-checkout-graph {
   display: none;
   position: relative;
   width: 690px;
   max-width: 100%;
   margin: 6px 0 0 0;
   box-sizing: border-box;
   overflow: visible;
 }

 .robokassa-checkout-graph.is-active {
   display: block;
 }

 .robokassa-checkout-graph robokassa-graph {
   display: block;
   width: 690px;
   max-width: 100%;
   box-sizing: border-box;
 }
</style>
{% endif %}

$robokassa_installment_map = array(
  'robokassa_podeli' => 'podeli',
  'robokassa_credit' => 'otp',
  'robokassa_mokka' => 'mokka',
  'robokassa_sbp' => 'sbp',
  'robokassa_yandex_split' => 'yandexpaysplit',
  'robokassa_split' => 'yandexpaysplit'
);
$robokassa_bnpl_aliases = array('podeli', 'otp', 'mokka', 'yandexpaysplit');
$robokassa_installment_aliases = array();
$robokassa_methods_initialized = (int)$this->config->get('payment_robokassa_methods_initialized') === 1;
$robokassa_current_login = trim((string)$this->config->get('payment_robokassa_login'));
$robokassa_saved_login = trim((string)$this->config->get('payment_robokassa_methods_login'));
$robokassa_merchant_login = ($robokassa_methods_initialized && $robokassa_current_login !== '' && $robokassa_saved_login === $robokassa_current_login) ? $robokassa_saved_login : '';

if ($robokassa_merchant_login !== '') {
  $robokassa_currency_url = 'https://auth.robokassa.ru/Merchant/WebService/Service.asmx/GetCurrencies?MerchantLogin=' . rawurlencode($robokassa_merchant_login) . '&Language=ru';
  $robokassa_currency_xml = false;

  if (function_exists('curl_init')) {
    $robokassa_ch = curl_init($robokassa_currency_url);
    curl_setopt($robokassa_ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($robokassa_ch, CURLOPT_CONNECTTIMEOUT, 3);
    curl_setopt($robokassa_ch, CURLOPT_TIMEOUT, 3);
    $robokassa_currency_xml = curl_exec($robokassa_ch);
    curl_close($robokassa_ch);
  }

  if ($robokassa_currency_xml === false && ini_get('allow_url_fopen')) {
    $robokassa_currency_context = stream_context_create(array(
      'http' => array(
        'timeout' => 3
      )
    ));
    $robokassa_currency_xml = @file_get_contents($robokassa_currency_url, false, $robokassa_currency_context);
  }

  if ($robokassa_currency_xml !== false && strpos($robokassa_currency_xml, '<Code>0</Code>') !== false && preg_match_all('/\bAlias="([^"]+)"/i', $robokassa_currency_xml, $robokassa_aliases_match)) {
    foreach ($robokassa_aliases_match[1] as $robokassa_alias) {
      $robokassa_installment_aliases[] = strtolower((string)$robokassa_alias);
    }

    $robokassa_installment_aliases = array_unique($robokassa_installment_aliases);
  }
}

if ($extension == 'payment' && $files) {
  $robokassa_installment_map = array(
    'robokassa_podeli' => 'podeli',
    'robokassa_credit' => 'otp',
    'robokassa_mokka' => 'mokka',
    'robokassa_sbp' => 'sbp',
    'robokassa_yandex_split' => 'yandexpaysplit',
    'robokassa_split' => 'yandexpaysplit'
  );
  $robokassa_bnpl_aliases = array('podeli', 'otp', 'mokka', 'yandexpaysplit');
  $robokassa_installment_aliases = array();
  $robokassa_methods_initialized = (int)$this->config->get('payment_robokassa_methods_initialized') === 1;
  $robokassa_current_login = trim((string)$this->config->get('payment_robokassa_login'));
  $robokassa_saved_login = trim((string)$this->config->get('payment_robokassa_methods_login'));
  $robokassa_merchant_login = ($robokassa_methods_initialized && $robokassa_current_login !== '' && $robokassa_saved_login === $robokassa_current_login) ? $robokassa_saved_login : '';

  if ($robokassa_merchant_login !== '') {
    $robokassa_currency_url = 'https://auth.robokassa.ru/Merchant/WebService/Service.asmx/GetCurrencies?MerchantLogin=' . rawurlencode($robokassa_merchant_login) . '&Language=ru';
    $robokassa_currency_xml = false;

    if (function_exists('curl_init')) {
      $robokassa_ch = curl_init($robokassa_currency_url);
      curl_setopt($robokassa_ch, CURLOPT_RETURNTRANSFER, true);
      curl_setopt($robokassa_ch, CURLOPT_CONNECTTIMEOUT, 3);
      curl_setopt($robokassa_ch, CURLOPT_TIMEOUT, 3);
      $robokassa_currency_xml = curl_exec($robokassa_ch);
      curl_close($robokassa_ch);
    }

    if ($robokassa_currency_xml === false && ini_get('allow_url_fopen')) {
      $robokassa_currency_context = stream_context_create(array(
        'http' => array(
          'timeout' => 3
        )
      ));
      $robokassa_currency_xml = @file_get_contents($robokassa_currency_url, false, $robokassa_currency_context);
    }

    if ($robokassa_currency_xml !== false && strpos($robokassa_currency_xml, '<Code>0</Code>') !== false && preg_match_all('/\bAlias="([^"]+)"/i', $robokassa_currency_xml, $robokassa_aliases_match)) {
      foreach ($robokassa_aliases_match[1] as $robokassa_alias) {
        $robokassa_installment_aliases[] = strtolower((string)$robokassa_alias);
      }

      $robokassa_installment_aliases = array_unique($robokassa_installment_aliases);
    }
  }

  $robokassa_payment_files = array();

  foreach ($files as $robokassa_file) {
    $robokassa_code = basename($robokassa_file, '.php');

    if (isset($robokassa_installment_map[$robokassa_code]) && !in_array($robokassa_installment_map[$robokassa_code], $robokassa_installment_aliases, true)) {
      continue;
    }

    if ($robokassa_code == 'robokassa_widget' && !array_intersect($robokassa_bnpl_aliases, $robokassa_installment_aliases)) {
      continue;
    }

    $robokassa_payment_files[] = $robokassa_file;
  }

  $files = $robokassa_payment_files;
}
